// Cron job configuration example
// Create in Config Center → Cron Jobs

// Task name: Daily Briefing
// Cron expression: 0 8 * * * (Daily at 8:00 AM)
// Prompt:

Please prepare my daily briefing:

1. **Today's Weather** — Check the weather forecast for my city
2. **Important News** — Search for 3 important tech/AI news stories today, briefly summarize
3. **Todo Reminders** — Check my MEMORY.md for items due today
4. **Schedule Suggestions** — Based on weather and todos, suggest an action plan for today

Please output in a concise format, separate each section with emoji headings.

// hooks.mappings configuration example
// Add the following mappings in Config Center → Hooks

// Mapping 1: GitHub Push event → Notify via Telegram
{
  "id": "github-push",
  "match": {
    "path": "/github",
    "source": "github"
  },
  "action": "agent",
  "messageTemplate": "GitHub Push event: {{body.repository.full_name}} received {{body.commits.length}} commits, latest: {{body.head_commit.message}}",
  "channel": "telegram",
  "to": "YOUR_CHAT_ID"
}

// Mapping 2: GitHub PR event → Wake AI for analysis
{
  "id": "github-pr",
  "match": {
    "path": "/github-pr"
  },
  "action": "agent",
  "messageTemplate": "New PR needs review: {{body.pull_request.title}} by {{body.pull_request.user.login}}, please analyze changes and provide suggestions.",
  "channel": "telegram",
  "model": "claude-sonnet"
}

// Mapping 3: Generic Webhook → Wake heartbeat
{
  "id": "generic-wake",
  "match": {
    "path": "/wake"
  },
  "action": "wake",
  "wakeMode": "now"
}

// Tool policy configuration examples
// Configure in Config Center → Tools or Config Center → JSON Editor

// ═══════════════════════════════════════
// Plan 1: Full Trust (Personal use)
// ═══════════════════════════════════════
"tools": {
  "profile": "full"
}

// ═══════════════════════════════════════
// Plan 2: Coding Mode (No messaging)
// ═══════════════════════════════════════
"tools": {
  "profile": "coding",
  "deny": ["message_send", "message_broadcast"]
}

// ═══════════════════════════════════════
// Plan 3: Safe Mode (Chat + Web search only)
// ═══════════════════════════════════════
"tools": {
  "profile": "messaging",
  "web": {
    "search": { "enabled": true },
    "fetch": { "enabled": true, "maxChars": 50000 }
  }
}

// ═══════════════════════════════════════
// Plan 4: Per-provider permissions
// ═══════════════════════════════════════
"tools": {
  "profile": "full",
  "byProvider": {
    "openai": { "profile": "coding" },
    "anthropic": { "profile": "full" }
  }
}

// ═══════════════════════════════════════
// Plan 5: Command execution hardening
// ═══════════════════════════════════════
"tools": {
  "profile": "coding",
  "exec": {
    "allowlist": ["git *", "npm *", "node *"],
    "denylist": ["rm -rf *", "sudo *"]
  }
}
